const query = $input.first().json.query || {};
const id = query.id || '';
if (!id) throw new Error('Falta id en query params');
const isUUID = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id);
return [{ json: { idBuscar: id, isUUID } }];

// Pasar el resultado de fichas junto con el ID buscado
const fichas = $input.all().map(i => i.json).filter(x => x.id);
const { idBuscar, isUUID } = $('Extraer ID CF').first().json;
return [{ json: { idBuscar, isUUID, fichas } }];

// Combinar fichas + solicitudes y buscar por id
const { idBuscar, isUUID, fichas } = $('Empaquetar Fichas').first().json;
const solicitudes = $input.all().map(i => i.json).filter(x => x.id);

let result = null;

if (isUUID) {
  const ficha = fichas.find(f => f.id === idBuscar);
  if (ficha) {
    result = {
      'ID': ficha.id,
      'id': ficha.id,
      'Comercial': ficha.comercial || '',
      'Nombre Sociedad': ficha.denominacion || '',
      'Nombre Comercial': ficha.nombre_comercial || '',
      'Calle': ficha.calle || '',
      'Número': ficha.numero || '',
      'CP': ficha.cp || '',
      'Municipio': ficha.municipio || '',
      'Provincia': ficha.provincia || '',
      'CIF/NIF': ficha.cif || '',
      'Email': ficha.email || '',
      'Email Factura': ficha.email_factura || '',
      'Email CC': ficha.email_cc || '',
      'Tipo Cliente': ficha.tipo_cliente || '',
      'JP Nombre': ficha.jp_nombre || '',
      'JP Apellidos': ficha.jp_apellidos || '',
      'JP Rol': ficha.jp_rol || '',
      'JP Teléfono': ficha.jp_telefono || '',
      'JP Mail': ficha.jp_mail || '',
      'Firmante Nombre': ficha.firm_nombre || '',
      'Firmante Apellidos': ficha.firm_apellidos || '',
      'Firmante Mail': ficha.firm_mail || '',
      'Firmante DNI': ficha.firm_dni || '',
      'Firmante Puesto': ficha.firm_puesto || '',
      'TPV': ficha.tpv || '',
      'TPV Contacto': ficha.tpv_contacto || '',
      'TPV Email': ficha.tpv_email || '',
      'TPV No Integrado': ficha.tpv_no_integrado === true ? 'Sí' : '',
      'TPV NI Nombre': ficha.tpv_ni_nombre || '',
      'TPV NI Contacto': ficha.tpv_ni_contacto || '',
      'TPV NI Email': ficha.tpv_ni_email || '',
      'Credencial Master': ficha.cred_master || '',
      'Credencial Yurest': ficha.cred_yurest || '',
      'Comentarios': ficha.comentarios || '',
      'Estado': ficha.estado || '',
      'Baja': ficha.baja || 'No',
      'Lite': ficha.lite === true ? 'Sí' : '',
      'Distribuidor': ficha.distribuidor === true ? 'Sí' : '',
      'Módulos': Array.isArray(ficha.modulos) ? ficha.modulos.join(',') : (ficha.modulos || ''),
      'Dist. Empresa': ficha.dist_empresa || '',
      'Dist. CIF': ficha.dist_cif || '',
      'Dist. Dirección': ficha.dist_direccion || '',
      'Dist. CP': ficha.dist_cp || '',
      'Dist. Contacto': ficha.dist_contacto || '',
      'Dist. Mail': ficha.dist_mail || '',
      'Dist. Teléfono': ficha.dist_telefono || '',
      'ImporteSetup': ficha.importe_setup || '',
      'Descuentosetup': ficha.descuento_setup || ''
    };
  }
}

if (!result) {
  for (const sol of solicitudes) {
    let datos = sol.datos;
    if (typeof datos === 'string') {
      try { datos = JSON.parse(datos); } catch(_) { datos = {}; }
    }
    const solId = datos['ID Solicitud'] || '';
    if (String(solId) === String(idBuscar) || sol.id === idBuscar) {
      result = datos;
      result.id = sol.id;
      result['ID Solicitud'] = solId;
      break;
    }
  }
}

if (!result) {
  result = { id: idBuscar, 'ID Solicitud': idBuscar };
}

return [{ json: result }];
